    // ── Issue grouping (replaces old pipeline tests) ─────────────────────────

    fn make_assignment_typed(
        status: &str,
        issue: u64,
        repo: &str,
        atype: Option<&str>,
    ) -> Assignment {
        Assignment {
            id: format!("id-{}-{}", issue, status),
            repo: repo.to_string(),
            issue_number: issue,
            issue_title: format!("Issue {}", issue),
            machine: "testmachine".to_string(),
            status: status.to_string(),
            branch: None,
            model: None,
            dispatched_at: Some(1_000_000.0 + issue as f64),
            finished_at: None,
            exit_code: None,
            assignment_type: atype.map(|s| s.to_string()),
            test_state: None,
            review_verdict: None,
            review_of_assignment_id: None,
            cost_usd: None,
            smoke_tests: None,
            review_findings: None,
            test_plan: None,
            test_plan_branch_head: None,
            input_tokens: 0,
            output_tokens: 0,
            cache_creation_tokens: 0,
            cache_read_tokens: 0,
            is_interactive: false,
            failure_reason: None,
        }
    }

    #[test]
    fn issues_by_repo_deduplicates_issues() {
        let assignments = vec![
            make_assignment_typed("running", 10, "repo-a", Some("work")),
            make_assignment_typed("done", 10, "repo-a", Some("plan")),
            make_assignment_typed("done", 20, "repo-b", Some("work")),
        ];
        let app = make_app_with_assignments(assignments);
        let grouped = app.issues_by_repo();
        // Two repos, one issue each.
        let total_issues: usize = grouped.iter().map(|(_, issues)| issues.len()).sum();
        assert_eq!(total_issues, 2);
    }

    // ── Leg 2 (#517): auto-advance Work → Review ─────────────────────────

    fn done_work_with_branch(issue: u64, repo: &str) -> Assignment {
        let mut a = make_assignment_typed("done", issue, repo, Some("work"));
        a.branch = Some(format!("issue-{}-work", issue));
        a
    }

    fn arm_auto_review(app: &mut CoordApp, repo: &str, issue: u64, prior: &[&str]) {
        app.armed_for_auto_review.insert(
            (repo.to_string(), issue),
            ArmedAutoReview {
                coord_repo: repo.to_string(),
                repo_slug: repo.to_string(),
                issue_num: issue,
                prior_done_ids: prior.iter().map(|s| s.to_string()).collect(),
            },
        );
    }

    fn mk_pending_auto_review(repo: &str, issue: u64) -> PendingAutoReview {
        PendingAutoReview {
            coord_repo: repo.to_string(),
            repo_slug: repo.to_string(),
            issue_num: issue,
        }
    }

    #[test]
    fn detect_completed_interactive_work_fires_on_new_done_work() {
        let mut app = make_app_with_assignments(vec![done_work_with_branch(10, "repo-a")]);
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        assert!(app.detect_completed_interactive_work());
        // Test precedes Review: a finished work offers the Test stage first.
        let p = app.pending_stage_launch.as_ref().expect("prompt raised");
        assert_eq!(p.kind, StageLaunchKind::Test);
        assert_eq!(p.issue_num, 10);
        assert_eq!(p.coord_repo, "repo-a");
        // Armed entry consumed so the prompt doesn't re-fire next tick.
        assert!(app.armed_for_auto_review.is_empty());
    }

    #[test]
    fn detect_ignores_preexisting_completion() {
        // The done work aid was ALREADY done at arm time → not a new finish,
        // so a redo that hasn't completed yet must not auto-prompt.
        let mut app = make_app_with_assignments(vec![done_work_with_branch(10, "repo-a")]);
        arm_auto_review(&mut app, "repo-a", 10, &["id-10-done"]);
        assert!(!app.detect_completed_interactive_work());
        assert!(app.pending_stage_launch.is_none());
        // Stays armed, waiting for a genuinely new completion.
        assert!(app
            .armed_for_auto_review
            .contains_key(&("repo-a".to_string(), 10)));
    }

    fn review_of(work_id: &str, issue: u64, repo: &str, verdict: Option<&str>) -> Assignment {
        let mut a = make_assignment_typed("done", issue, repo, Some("review"));
        a.id = format!("rev-{}-{}", issue, work_id);
        a.review_of_assignment_id = Some(work_id.to_string());
        a.review_verdict = verdict.map(|v| v.to_string());
        // Reviews are dispatched after the work they target.
        a.dispatched_at = Some(2_000_000.0 + issue as f64);
        a
    }

    #[test]
    fn detect_skips_when_latest_work_already_reviewed() {
        // The latest work already has a review targeting it → no auto-prompt
        // (a review is in flight / done for THIS work).
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review_of("id-10-done", 10, "repo-a", None),
        ]);
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        assert!(!app.detect_completed_interactive_work());
        assert!(app.pending_stage_launch.is_none());
    }

    #[test]
    fn detect_re_test_fires_after_a_fix_even_with_a_prior_review() {
        // Original work reviewed (request-changes); a FIX produced a NEW done
        // work aid that has no test verdict yet → re-test must fire (Test
        // precedes Review, so a fix re-tests before its incremental re-review;
        // the old review must NOT block it).
        let mut fix = make_assignment_typed("done", 10, "repo-a", Some("work"));
        fix.id = "id-10-fix".to_string();
        fix.branch = Some("issue-10-work".to_string());
        fix.dispatched_at = Some(3_000_000.0); // newer than original work + review
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"), // id-10-done (original)
            review_of("id-10-done", 10, "repo-a", Some("request-changes")),
            fix, // id-10-fix — the latest work, not yet tested
        ]);
        // Armed at fix-launch time: only the ORIGINAL work was done then.
        arm_auto_review(&mut app, "repo-a", 10, &["id-10-done"]);
        assert!(app.detect_completed_interactive_work());
        let p = app.pending_stage_launch.as_ref().expect("re-test offer raised");
        assert_eq!(p.kind, StageLaunchKind::Test);
        assert_eq!(p.issue_num, 10);
    }

    #[test]
    fn detect_no_fire_while_work_still_running() {
        let mut app = make_app_with_assignments(vec![make_assignment_typed(
            "running",
            10,
            "repo-a",
            Some("work"),
        )]);
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        assert!(!app.detect_completed_interactive_work());
        assert!(app.pending_stage_launch.is_none());
    }

    #[test]
    fn detect_no_fire_when_done_work_has_no_branch() {
        // Done but no branch (aborted, no commits) → nothing to review.
        let mut app = make_app_with_assignments(vec![make_assignment_typed(
            "done",
            10,
            "repo-a",
            Some("work"),
        )]);
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        assert!(!app.detect_completed_interactive_work());
    }

    #[test]
    fn detect_no_fire_when_a_prompt_is_already_open() {
        let mut app = make_app_with_assignments(vec![done_work_with_branch(10, "repo-a")]);
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        app.pending_auto_review = Some(mk_pending_auto_review("repo-b", 99));
        assert!(!app.detect_completed_interactive_work());
        // The unrelated open prompt is left untouched (one at a time).
        assert_eq!(app.pending_auto_review.as_ref().unwrap().issue_num, 99);
        // …and the armed entry survives for the next tick.
        assert!(app
            .armed_for_auto_review
            .contains_key(&("repo-a".to_string(), 10)));
    }

    #[test]
    fn auto_review_prompt_suppresses_panel_toolbar() {
        let mut app = make_app_default();
        assert!(app.panel_toolbar().is_some());
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        assert!(app.panel_toolbar().is_none());
    }

    #[test]
    fn build_prompt_dialog_returns_auto_review_dialog() {
        let mut app = make_app_default();
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 42));
        let dialog = app.build_prompt_dialog().expect("auto-review dialog");
        assert_eq!(dialog.id, WidgetId::new("dialog:auto-review"));
        assert!(dialog
            .buttons
            .iter()
            .any(|b| b.id == WidgetId::new("review")));
        // Body names the issue so the operator knows which review this is.
        let body_text: String = dialog
            .body
            .iter()
            .flat_map(|b| b.spans.iter())
            .map(|s| s.text.as_str())
            .collect::<Vec<_>>()
            .join(" ");
        assert!(
            body_text.contains("#42"),
            "dialog body should name the issue, got: {body_text}",
        );
    }

    #[test]
    fn dismiss_prompt_dialog_clears_auto_review() {
        let mut app = make_app_default();
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        app.dismiss_prompt_dialog();
        assert!(app.pending_auto_review.is_none());
    }

    #[test]
    fn confirm_auto_review_without_matching_row_is_noop() {
        // Empty pipeline_issues → no row to select; confirm consumes the
        // prompt, toasts, and spawns no terminal session (no panic).
        let mut app = make_app_default();
        app.pending_auto_review = Some(mk_pending_auto_review("repo-a", 10));
        app.confirm_auto_review();
        assert!(app.pending_auto_review.is_none());
        assert!(app.detail_terminal_sessions.is_empty());
    }

    // ── Leg 3 (#517): verdict-driven routing ─────────────────────────────

    fn arm_verdict(app: &mut CoordApp, repo: &str, issue: u64, prior: &[&str]) {
        app.armed_for_verdict.insert(
            (repo.to_string(), issue),
            ArmedVerdict {
                coord_repo: repo.to_string(),
                repo_slug: repo.to_string(),
                issue_num: issue,
                prior_verdicted_ids: prior.iter().map(|s| s.to_string()).collect(),
            },
        );
    }

    fn mk_pending_rework(repo: &str, issue: u64) -> PendingRework {
        PendingRework {
            coord_repo: repo.to_string(),
            repo_slug: repo.to_string(),
            issue_num: issue,
            findings: String::new(),
        }
    }

    #[test]
    fn detect_review_verdict_request_changes_raises_rework() {
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review_of("id-10-done", 10, "repo-a", Some("request-changes")),
        ]);
        arm_verdict(&mut app, "repo-a", 10, &[]);
        assert!(app.detect_review_verdict());
        let p = app.pending_rework.as_ref().expect("rework prompt raised");
        assert_eq!(p.issue_num, 10);
        // Armed entry consumed so it doesn't re-route next tick.
        assert!(app.armed_for_verdict.is_empty());
    }

    #[test]
    fn detect_review_verdict_request_changes_skips_prompt_when_findings_present() {
        // When the review agent already self-reported findings to the DB
        // (`coord report-result`), the #587 manual-entry rework dialog is
        // redundant — detect_review_verdict raises a one-key "start fix" stage
        // offer instead, so the operator never has to retype the findings.
        let mut review = review_of("id-10-done", 10, "repo-a", Some("request-changes"));
        review.review_findings = Some(
            r#"{"verdict":"request-changes","body":"Missing keyboard-nav tests."}"#.to_string(),
        );
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review,
        ]);
        arm_verdict(&mut app, "repo-a", 10, &[]);
        assert!(app.detect_review_verdict());
        assert!(
            app.pending_rework.is_none(),
            "the #587 findings dialog must be skipped when findings are already in the DB",
        );
        let p = app
            .pending_stage_launch
            .as_ref()
            .expect("a start-fix stage offer is raised");
        assert_eq!(p.kind, StageLaunchKind::Fix);
        assert_eq!(p.issue_num, 10);
        assert!(app.armed_for_verdict.is_empty());
    }

    #[test]
    fn review_assignment_has_findings_requires_nonempty_body() {
        // None → false.
        let r0 = review_of("w", 10, "repo-a", Some("request-changes"));
        let aid0 = r0.id.clone();
        let app0 = make_app_with_assignments(vec![r0]);
        assert!(!app0.review_assignment_has_findings(&aid0));

        // Non-empty body → true.
        let mut r1 = review_of("w", 11, "repo-a", Some("request-changes"));
        let aid1 = r1.id.clone();
        r1.review_findings = Some(r#"{"verdict":"request-changes","body":"do x"}"#.to_string());
        let app1 = make_app_with_assignments(vec![r1]);
        assert!(app1.review_assignment_has_findings(&aid1));

        // Present JSON but blank body → false (no real findings to brief from).
        let mut r2 = review_of("w", 12, "repo-a", Some("request-changes"));
        let aid2 = r2.id.clone();
        r2.review_findings = Some(r#"{"verdict":"request-changes","body":"  "}"#.to_string());
        let app2 = make_app_with_assignments(vec![r2]);
        assert!(!app2.review_assignment_has_findings(&aid2));
    }

    #[test]
    fn detect_review_verdict_approve_notifies_without_rework() {
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review_of("id-10-done", 10, "repo-a", Some("approve")),
        ]);
        arm_verdict(&mut app, "repo-a", 10, &[]);
        // Approve → a one-key "start merge agent" offer (the branch was already
        // tested — Test precedes Review), never a rework prompt.
        assert!(app.detect_review_verdict());
        assert!(app.pending_rework.is_none());
        assert!(app.pending_stage_launch.is_none());
        let p = app
            .pending_merge
            .as_ref()
            .expect("a start-merge offer is raised");
        assert_eq!(p.issue_num, 10);
        assert!(app.armed_for_verdict.is_empty());
    }

    #[test]
    fn confirm_stage_launch_without_matching_row_is_noop() {
        // Empty pipeline → no row to select; confirm consumes the offer and
        // spawns no terminal session (mirrors confirm_auto_review's no-op).
        let mut app = make_app_default();
        app.pending_stage_launch = Some(PendingStageLaunch {
            coord_repo: "repo-a".to_string(),
            repo_slug: "repo-a".to_string(),
            issue_num: 10,
            kind: StageLaunchKind::Test,
        });
        app.confirm_stage_launch();
        assert!(app.pending_stage_launch.is_none());
        assert!(app.detail_terminal_sessions.is_empty());
    }

    #[test]
    fn detect_review_verdict_ignores_already_seen_verdict() {
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review_of("id-10-done", 10, "repo-a", Some("request-changes")),
        ]);
        // The verdicted review id was already in the arm-time snapshot.
        arm_verdict(&mut app, "repo-a", 10, &["rev-10-id-10-done"]);
        assert!(!app.detect_review_verdict());
        assert!(app.pending_rework.is_none());
        assert!(app
            .armed_for_verdict
            .contains_key(&("repo-a".to_string(), 10)));
    }

    #[test]
    fn detect_review_verdict_no_fire_while_review_running() {
        // Review dispatched but no verdict reported yet → nothing to route.
        let mut review = make_assignment_typed("running", 10, "repo-a", Some("review"));
        review.review_of_assignment_id = Some("id-10-done".to_string());
        let mut app =
            make_app_with_assignments(vec![done_work_with_branch(10, "repo-a"), review]);
        arm_verdict(&mut app, "repo-a", 10, &[]);
        assert!(!app.detect_review_verdict());
        assert!(app.pending_rework.is_none());
    }

    #[test]
    fn detect_review_verdict_skipped_while_a_prompt_is_open() {
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            review_of("id-10-done", 10, "repo-a", Some("request-changes")),
        ]);
        arm_verdict(&mut app, "repo-a", 10, &[]);
        app.pending_auto_review = Some(mk_pending_auto_review("repo-b", 99));
        assert!(!app.detect_review_verdict());
        assert!(app.pending_rework.is_none());
        assert!(app
            .armed_for_verdict
            .contains_key(&("repo-a".to_string(), 10)));
    }

    // ── #722: live remote session gates ──────────────────────────────────────
    //
    // A running tmux session on a remote fleet machine (`live_tmux_sessions`)
    // must defer stage-advance detectors and block confirm handlers, mirroring
    // the existing `session_pane_live` guard for embedded panes (#602).

    /// Build a `LiveTmuxSession` for `issue` on `repo`, backed by a "running"
    /// assignment already present in the app's board data.  `assignment_id`
    /// must match an entry in `data.assignments` with `status == "running"` so
    /// that `session_assignment_is_running` returns true and
    /// `issue_has_live_session` counts the entry.
    fn make_live_tmux_session(
        assignment_id: &str,
        issue: u64,
        repo: &str,
    ) -> LiveTmuxSession {
        LiveTmuxSession {
            assignment_id: assignment_id.to_string(),
            issue_number: Some(issue),
            repo_name: Some(repo.to_string()),
            issue_title: None,
            machine: Some("precision".to_string()),
            pane_dead: false,
        }
    }

    #[test]
    fn live_session_defers_detect_completed_interactive_work() {
        // Work is done (has a branch) AND a running tmux session exists for the
        // issue — the detector must defer (leave the armed entry for re-check
        // on the next tick when the session closes).
        let running_work = make_assignment_typed("running", 10, "repo-a", Some("work"));
        let running_aid = running_work.id.clone();
        let mut app = make_app_with_assignments(vec![
            done_work_with_branch(10, "repo-a"),
            running_work,
        ]);
        app.live_tmux_sessions.push(make_live_tmux_session(&running_aid, 10, "repo-a"));
        arm_auto_review(&mut app, "repo-a", 10, &[]);
        // Detector must NOT fire while the remote session is live.
        assert!(!app.detect_completed_interactive_work());
        assert!(app.pending_stage_launch.is_none());
        // Armed entry preserved so the offer re-fires once the session closes.
        assert!(app.armed_for_auto_review.contains_key(&("repo-a".to_string(), 10)));
    }

