    // ── repo_tag: collision-safe single-letter tags ────────────────────────

    /// Helper to make a small Vec<String> for repo_tag calls.
    fn repos(names: &[&str]) -> Vec<String> {
        names.iter().map(|s| s.to_string()).collect()
    }

    #[test]
    fn repo_tag_single_repo_returns_first_char_uppercased() {
        assert_eq!(CoordApp::repo_tag("quadraui", &repos(&["quadraui"])), "Q");
        assert_eq!(CoordApp::repo_tag("vimcode", &repos(&["vimcode"])), "V");
    }

    #[test]
    fn repo_tag_no_collision_returns_first_char() {
        // Three repos with unique first letters — each gets a single char.
        let all = repos(&["claude-coordinator", "quadraui", "vimcode"]);
        assert_eq!(CoordApp::repo_tag("claude-coordinator", &all), "C");
        assert_eq!(CoordApp::repo_tag("quadraui", &all), "Q");
        assert_eq!(CoordApp::repo_tag("vimcode", &all), "V");
    }

    #[test]
    fn repo_tag_collision_extends_to_shortest_unique_prefix() {
        // "claude-coordinator" and "coord-something" both start with 'c'.
        // Shortest unique prefixes are "cl" and "co".
        let all = repos(&["claude-coordinator", "coord-something"]);
        assert_eq!(CoordApp::repo_tag("claude-coordinator", &all), "Cl");
        assert_eq!(CoordApp::repo_tag("coord-something", &all), "Co");
    }

    #[test]
    fn repo_tag_three_way_collision_extends_appropriately() {
        // Three repos sharing first letter 'a'.
        let all = repos(&["alpha", "apricot", "azure"]);
        // "al" uniquely identifies "alpha", "ap" → "apricot", "az" → "azure".
        assert_eq!(CoordApp::repo_tag("alpha", &all), "Al");
        assert_eq!(CoordApp::repo_tag("apricot", &all), "Ap");
        assert_eq!(CoordApp::repo_tag("azure", &all), "Az");
    }

    #[test]
    fn repo_tag_case_insensitive_collision_detection() {
        // Collision detection ignores case.
        let all = repos(&["Foo", "fuzz"]);
        assert_eq!(CoordApp::repo_tag("Foo", &all), "Fo");
        assert_eq!(CoordApp::repo_tag("fuzz", &all), "Fu");
    }

    #[test]
    fn pipeline_active_section_rows_have_repo_tag_badge_and_flat_path() {
        // In-progress issues must appear as flat rows with a single-letter
        // repo tag badge.  New / Refining / Pending / Done rows use path
        // [ri, ii].
        let mut app = make_pipeline_app();
        // Make issue #42 active (add an assignment).
        app.data
            .assignments
            .push(make_assignment_typed("running", 42, "api", Some("work")));
        app.rebuild_pipeline_sidebar(None);

        // The In-progress section must be present (per #194 ordering it sits
        // between Pending and Done, not necessarily first).
        assert!(
            app.pipeline_state_section_names.contains(&"in-progress"),
            "In-progress section must be present when a work assignment exists",
        );
        // The selected issue resolves correctly via the flat path.
        let idx = app.pipeline_active_issues();
        assert!(!idx.is_empty(), "active_flat must be non-empty");
    }

    #[test]
    fn pipeline_new_done_sections_grouped_by_repo() {
        // New section must sub-group by repo.
        // Done section (#728) is now flat/windowed — verify it shows the closed
        // issue when done_window == All (no finished_at on the test issue).
        let mut app = make_pipeline_app();
        // Add a closed issue in the second repo.
        app.pipeline_issues.push(PipelineIssue {
            number: 100,
            title: "Closed other".to_string(),
            body: String::new(),
            repo_slug: "other/repo".to_string(),
            coord_repo: None,
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string()],
            is_closed: true,
        });
        // #728: issues without finished_at are hidden in the default H2 window;
        // set All so the test can observe the Done section.
        app.done_window = DoneWindow::All;
        app.rebuild_pipeline_sidebar(None);

        // State sections: New + Done (#628: status:ready issues are "new").
        assert!(
            app.pipeline_state_section_names.contains(&"new"),
            "New section must exist",
        );
        assert!(
            app.pipeline_state_section_names.contains(&"done"),
            "Done section must exist",
        );

        // New section has 2 repos with 1 issue each.
        let new_groups = app.pipeline_repos_for_state("new");
        assert_eq!(new_groups.len(), 2, "New section has two repos");

        // Done section (#728): flat windowed list — 1 item (issue #100).
        let done_windowed = app.pipeline_done_windowed();
        assert_eq!(done_windowed.len(), 1, "Done windowed list has one item");
    }

    // ── #193: stale downstream stages ─────────────────────────────────────────

    /// Helper: an assignment of `kind` (work/review/etc.) for issue 42 on `api`
    /// at the given dispatched_at, terminal status `done` unless overridden.
    fn _stage_assignment(id: &str, kind: &str, dispatched_at: f64, status: &str) -> Assignment {
        Assignment {
            id: id.to_string(),
            repo: "api".to_string(),
            issue_number: 42,
            issue_title: "Add cool thing".to_string(),
            machine: "m1".to_string(),
            status: status.to_string(),
            branch: None,
            model: None,
            dispatched_at: Some(dispatched_at),
            finished_at: Some(dispatched_at + 60.0),
            exit_code: if status == "failed" { Some(1) } else { Some(0) },
            assignment_type: Some(kind.to_string()),
            test_state: None,
            // #473: a *done* review in these stage-status fixtures means
            // "approved" (green) — the stage colour now keys on the verdict,
            // not just status=done, so the fixture must carry it.
            review_verdict: if kind == "review" && status == "done" {
                Some("approve".to_string())
            } else {
                None
            },
            review_of_assignment_id: None,
            cost_usd: None,
            smoke_tests: None,
            review_findings: None,
            test_plan: None,
            test_plan_branch_head: None,
            input_tokens: 0,
            output_tokens: 0,
            cache_creation_tokens: 0,
            cache_read_tokens: 0,
            is_interactive: false,
            failure_reason: None,
        }
    }

    #[test]
    fn stage_status_stale_when_upstream_redispatched_after_done() {
        // The user's #214 case: Work was re-dispatched after a request-changes
        // review. Previously Review showed Done (green); should now show Stale.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "done"));
        // Work re-dispatched (later than the review).
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "work"), StageStatus::Done);
        assert_eq!(app.stage_status_for(issue, "review"), StageStatus::Stale);
    }

    #[test]
    fn stage_status_stale_when_upstream_redispatched_after_failed() {
        // A Failed review against an older Work is still Stale once Work re-runs:
        // the failure was about a diff that no longer exists.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "failed"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "review"), StageStatus::Stale);
    }

    #[test]
    fn stage_status_done_when_no_upstream_redispatch() {
        // Same setup minus the re-dispatch → Review stays Done (still trustworthy).
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "review"), StageStatus::Done);
    }

    #[test]
    fn stage_status_first_stage_never_stale() {
        // Work is the first dispatchable stage; there's no upstream to invalidate
        // it. Even with multiple dispatched_at values, latest wins as Done.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "work"), StageStatus::Done);
    }

    #[test]
    fn stage_status_active_beats_staleness_when_upstream_running() {
        // If a stage has a Running assignment, that wins over any verdict —
        // staleness only matters for terminal states.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "running"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "review"), StageStatus::Active);
    }

    #[test]
    fn upstream_max_dispatched_at_returns_none_for_first_stage() {
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.upstream_max_dispatched_at(issue, "work"), None);
    }

    #[test]
    fn upstream_max_dispatched_at_aggregates_across_all_prior_stages() {
        // #738: Pipeline is work → review (merge removed from per-issue stages).
        // Querying upstream of "review" should see the latest dispatch across
        // ALL prior work assignments.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 250.0, "done"));
        let issue = &app.pipeline_issues[0];
        // Max across {work} prior to review = 250 (the second work dispatch).
        assert_eq!(app.upstream_max_dispatched_at(issue, "review"), Some(250.0));
        // "merge" is no longer a per-issue stage → upstream lookup returns None.
        assert_eq!(app.upstream_max_dispatched_at(issue, "merge"), None, "#738: merge not in stage list");
    }

    #[test]
    fn pipeline_widget_attaches_retry_to_stale_stage_when_prior_settled() {
        // Stale + upstream Done → [Retry] button so the user can re-run.
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "done"));
        app.pipeline_sel = Some(0);
        let view = app.build_pipeline_widget().expect("widget");
        // Stage layout: work, review, merge.
        let review = &view.stages[1];
        assert_eq!(review.status, StageStatus::Stale);
        assert_eq!(review.action.as_deref(), Some("Retry"));
    }

    #[test]
    fn pipeline_widget_no_retry_on_stale_when_upstream_still_active() {
        // Stale + upstream Running → no button (waiting for upstream to settle
        // before user can act).
        let mut app = make_pipeline_app();
        app.data
            .assignments
            .push(_stage_assignment("w1", "work", 100.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("r1", "review", 200.0, "done"));
        app.data
            .assignments
            .push(_stage_assignment("w2", "work", 300.0, "running"));
        app.pipeline_sel = Some(0);
        let view = app.build_pipeline_widget().expect("widget");
        let review = &view.stages[1];
        assert_eq!(review.status, StageStatus::Stale);
        assert_eq!(review.action, None);
    }

    // ── #200: Test gate ──────────────────────────────────────────────────────

    /// Build a pipeline app whose default gates include "test" (the production
    /// default). The make_pipeline_app fixture uses ["review", "merge"] which
    /// predates #200; this helper inserts the Test gate.
    fn make_pipeline_app_with_test_gate() -> CoordApp {
        let mut app = make_pipeline_app();
        app.data.pipeline_default_gates = vec![
            "test".to_string(),
            "review".to_string(),
            "merge".to_string(),
        ];
        app
    }

    fn _work_assignment(
        id: &str,
        dispatched_at: f64,
        status: &str,
        test_state: Option<&str>,
    ) -> Assignment {
        let mut a = _stage_assignment(id, "work", dispatched_at, status);
        a.test_state = test_state.map(String::from);
        a
    }

    #[test]
    fn test_stage_pending_when_work_done_no_verdict() {
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", None));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Pending);
    }

    #[test]
    fn test_stage_done_when_passed() {
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("passed")));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Done);
    }

    #[test]
    fn test_stage_done_when_skipped() {
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("skipped")));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Done);
    }

    #[test]
    fn test_stage_active_while_interactive_smoke_running() {
        // #585: a prior automated pass left test_state="passed" (green), but the
        // operator opened an interactive smoke session (type="smoke"). The Test
        // box must read Active (blue) while it runs, then resolve back to the
        // recorded verdict when the session ends.
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("passed")));
        // No running smoke → Done (green).
        assert_eq!(
            app.stage_status_for(&app.pipeline_issues[0], "test"),
            StageStatus::Done
        );
        // Interactive testing agent running → Active (blue), over the pass.
        app.data
            .assignments
            .push(_stage_assignment("s1", "smoke", 200.0, "running"));
        assert_eq!(
            app.stage_status_for(&app.pipeline_issues[0], "test"),
            StageStatus::Active
        );
        // Session finished → back to the recorded verdict (Done).
        app.data.assignments.last_mut().unwrap().status = "done".to_string();
        assert_eq!(
            app.stage_status_for(&app.pipeline_issues[0], "test"),
            StageStatus::Done
        );
    }

    #[test]
    fn test_stage_survives_review_bounce_fix_work_with_no_verdict() {
        // #310: a review bounce creates a new fix-work assignment (dispatched
        // later) that carries no test_state. The earlier work genuinely passed.
        // Test must stay Done — reverting to Pending strands the Merge "Go"
        // button via prior_all_done.
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("passed")));
        app.data
            .assignments
            .push(_work_assignment("w2", 200.0, "done", None));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.test_stage_status_for(issue), StageStatus::Done);
    }

    #[test]
    fn test_stage_failed_when_later_retest_failed_after_prior_pass() {
        // A later fix-work that was actually re-tested and FAILED must win over
        // the earlier pass — the most recent carrier of a verdict decides.
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("passed")));
        app.data
            .assignments
            .push(_work_assignment("w2", 200.0, "done", Some("failed")));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.test_stage_status_for(issue), StageStatus::Failed);
    }

    #[test]
    fn test_stage_failed_when_failed_verdict() {
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("failed")));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Failed);
    }

    #[test]
    fn test_stage_pending_when_work_not_done() {
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "running", None));
        let issue = &app.pipeline_issues[0];
        // Work is Active → Test inherits Pending (nothing to gate yet).
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Pending);
    }

    #[test]
    fn test_stage_uses_latest_work_verdict() {
        // When a re-dispatched Work carries its OWN verdict, that latest
        // verdict controls — a stale older verdict must not leak through.
        // (The case where the latest fix-work has NO verdict is #310:
        // the prior pass is inherited — see
        // `test_stage_survives_review_bounce_fix_work_with_no_verdict`.)
        let mut app = make_pipeline_app_with_test_gate();
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", Some("failed")));
        app.data
            .assignments
            .push(_work_assignment("w2", 300.0, "done", Some("passed")));
        let issue = &app.pipeline_issues[0];
        assert_eq!(app.stage_status_for(issue, "test"), StageStatus::Done);
    }

    #[test]
    fn test_gate_actionable_only_when_pending_and_work_done() {
        let mut app = make_pipeline_app_with_test_gate();
        app.pipeline_sel = Some(0);
        // Empty board → no work yet → not actionable.
        assert!(!app.test_gate_actionable());
        // Add running work → still not actionable.
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "running", None));
        assert!(!app.test_gate_actionable());
        // Work done, no verdict → actionable.
        app.data.assignments[0].status = "done".into();
        assert!(app.test_gate_actionable());
        // Pass it → no longer actionable.
        app.data.assignments[0].test_state = Some("passed".into());
        assert!(!app.test_gate_actionable());
    }

    #[test]
    fn test_gate_not_actionable_when_no_test_in_pipeline() {
        // make_pipeline_app (no test gate configured) → never actionable.
        let mut app = make_pipeline_app();
        app.pipeline_sel = Some(0);
        app.data
            .assignments
            .push(_work_assignment("w1", 100.0, "done", None));
        assert!(!app.test_gate_actionable());
    }

