    #[test]
    fn pipeline_issues_from_cache_filters_maps_and_marks_closed() {
        // #486: the Pipeline now derives from the DB cache (data.open_issues),
        // not a live gh search.  Only tracked-labelled issues appear; repo
        // name maps to slug; closed issues are flagged for the Done section.
        let mk = |n: u64, state: &str, labels: &[&str]| OpenIssue {
            repo_name: "api".to_string(),
            number: n,
            title: format!("issue {n}"),
            body: String::new(),
            state: state.to_string(),
            labels: labels.iter().map(|s| s.to_string()).collect(),
            milestone_number: None,
            milestone_title: None,
        };
        let app = make_test_app(BoardData {
            pipeline_tracked_labels: vec!["coord".to_string()],
            pipeline_repos: vec![("api".to_string(), "acme/api".to_string())],
            open_issues: vec![
                mk(1, "open", &["coord", "status:ready"]),
                mk(2, "open", &["bug"]), // untracked → excluded
                mk(3, "closed", &["coord"]),
            ],
            ..BoardData::default()
        });
        let pis = app.pipeline_issues_from_cache();
        let nums: Vec<u64> = pis.iter().map(|p| p.number).collect();
        assert_eq!(nums, vec![1, 3], "only coord issues; #2 (untracked) excluded");
        assert_eq!(pis[0].repo_slug, "acme/api");
        assert_eq!(pis[0].coord_repo.as_deref(), Some("api"));
        assert!(pis[0].matched_labels.contains(&"coord".to_string()));
        assert!(!pis[0].is_closed);
        assert!(pis[1].is_closed, "#3 is closed → Done section");
    }

    #[test]
    fn merge_stage_ignores_same_number_issue_in_another_repo() {
        // #486: cc#276 (open, ready) must NOT inherit quadraui#276's merged
        // merge_queue state — matching merge entries by issue number alone made
        // an open issue get pinned to "Done" by a closed sibling in another
        // repo (the cross-repo issue-number collision).
        let app = make_test_app(BoardData {
            merge_queue: vec![MergeQueueEntry {
                assignment_id: "q".to_string(),
                issue_number: Some(276),
                state: "merged".to_string(),
                pr_number: None,
                pr_url: None,
                repo_github: "JDonaghy/quadraui".to_string(),
                target_branch: None,
                error: None,
                branch: None,
                milestone_title: None,
            }],
            ..BoardData::default()
        });
        let cc276 = PipelineIssue {
            number: 276,
            title: "cc".to_string(),
            body: String::new(),
            repo_slug: "JDonaghy/claude-coordinator".to_string(),
            coord_repo: Some("claude-coordinator".to_string()),
            matched_labels: vec!["coord".to_string()],
            all_labels: vec!["coord".to_string(), "status:ready".to_string()],
            is_closed: false,
        };
        assert_ne!(app.merge_stage_status_for(&cc276), StageStatus::Done);
        assert_eq!(
            app.pipeline_lifecycle_section(&cc276),
            "new",
            "open+ready cc#276 must be Pending, not Done from quadraui#276",
        );
    }

