    /// Regression for the silent-failure hole the reviewer flagged in
    /// iteration 2: when the user kicks off pull-artifact for work_A,
    /// then pull-artifact for work_B before A's result returns, the
    /// suppression must NOT fire on A's (now stale) result — otherwise
    /// the generic "Command failed" toast is hidden AND the dialog
    /// handler skips A (because pending_artifact_pull now points at B).
    /// Net result before this fix: zero user-visible feedback for A.
    #[test]
    fn should_suppress_command_failed_toast_only_for_matching_work_id() {
        // No pending pull at all → never suppress.
        assert!(!should_suppress_command_failed_toast(
            "pull-artifact work-A",
            None,
        ));

        // Pending pull for work-A, result is for work-A → suppress (the
        // dialog handler will pick it up).
        let pending_a = (
            "work-A".to_string(),
            "my-repo".to_string(),
            "issue-1".to_string(),
        );
        assert!(should_suppress_command_failed_toast(
            "pull-artifact work-A",
            Some(&pending_a),
        ));

        // Pending pull for work-B, result is for work-A → DO NOT suppress.
        // This is the iteration-2 silent-failure regression: A's failure
        // would otherwise be dropped on the floor.
        let pending_b = (
            "work-B".to_string(),
            "my-repo".to_string(),
            "issue-2".to_string(),
        );
        assert!(!should_suppress_command_failed_toast(
            "pull-artifact work-A",
            Some(&pending_b),
        ));

        // Pending pull for work-A but the result is some unrelated
        // command (e.g. `coord refine`) → DO NOT suppress; the
        // user still needs to see the refine failure.
        assert!(!should_suppress_command_failed_toast(
            "refine my-repo 42",
            Some(&pending_a),
        ));
    }

    /// Esc/Enter classify as `Dismiss` regardless of whether the dialog
    /// carries a path — drives the production classifier directly so a
    /// typo (e.g. `NamedKey::Escape` → `NamedKey::Back`) breaks tests.
    #[test]
    fn esc_and_enter_dismiss_artifact_pull_dialog() {
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Named(NamedKey::Escape), true),
            ArtifactDialogKeyOutcome::Dismiss,
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Named(NamedKey::Escape), false),
            ArtifactDialogKeyOutcome::Dismiss,
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Named(NamedKey::Enter), true),
            ArtifactDialogKeyOutcome::Dismiss,
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Named(NamedKey::Enter), false),
            ArtifactDialogKeyOutcome::Dismiss,
        );
    }

    /// `c`/`C` with a path copy and dismiss; without a path they fall
    /// through to `Swallow` (the failure dialog has nothing to copy).
    #[test]
    fn copy_key_classifies_correctly_with_and_without_path() {
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Char('c'), true),
            ArtifactDialogKeyOutcome::CopyAndDismiss,
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Char('C'), true),
            ArtifactDialogKeyOutcome::CopyAndDismiss,
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Char('c'), false),
            ArtifactDialogKeyOutcome::Swallow,
            "without a path, c must not dismiss",
        );
        assert_eq!(
            classify_artifact_pull_dialog_key(&Key::Char('C'), false),
            ArtifactDialogKeyOutcome::Swallow,
        );
    }

    /// Non-dismiss / non-copy keys are swallowed but do NOT close the
    /// dialog — guarantees arrow keys / Tab / etc. leave it visible.
    #[test]
    fn non_dismiss_keys_are_swallowed() {
        for key in [
            Key::Named(NamedKey::Tab),
            Key::Named(NamedKey::Up),
            Key::Named(NamedKey::Down),
            Key::Named(NamedKey::PageUp),
            Key::Named(NamedKey::PageDown),
            Key::Named(NamedKey::Home),
            Key::Named(NamedKey::End),
            Key::Char('x'),
            Key::Char('q'),
        ] {
            assert_eq!(
                classify_artifact_pull_dialog_key(&key, true),
                ArtifactDialogKeyOutcome::Swallow,
                "key {:?} must be Swallow (with path)",
                key,
            );
            assert_eq!(
                classify_artifact_pull_dialog_key(&key, false),
                ArtifactDialogKeyOutcome::Swallow,
                "key {:?} must be Swallow (no path)",
                key,
            );
        }
    }

    // ── #361: maybe_bind_pending_resume type-aware matching ───────────────────

    /// Helper: build a new assignment whose id differs from the old one so the
    /// `id != old_assignment_id` filter passes.
    fn make_resume_candidate(
        status: &str,
        issue: u64,
        atype: Option<&str>,
        new_id: &str,
    ) -> Assignment {
        let mut a = make_assignment_typed(status, issue, "repo-a", atype);
        a.id = new_id.to_string();
        // Use a large dispatched_at so the dispatch-floor filter (arm_unix_secs=0 → floor=-5)
        // always passes.
        a.dispatched_at = Some(2_000_000.0);
        a
    }

    /// Build a `PendingChatResume` with arm_unix_secs=0 (floor=-5, all rows
    /// pass the floor filter) so tests focus on the type-match logic only.
    fn make_pending_resume(old_id: &str, issue: u64, old_type: Option<&str>) -> PendingChatResume {
        PendingChatResume {
            old_assignment_id: old_id.to_string(),
            issue_number: issue,
            dispatched_at: Instant::now(),
            arm_unix_secs: 0.0,
            old_type: old_type.map(|s| s.to_string()),
        }
    }

    /// #361 regression: test-chat continuation must rebind when the new
    /// assignment is also "test-chat".
    #[test]
    fn maybe_bind_pending_resume_rebinds_test_chat() {
        let new_asg = make_resume_candidate("running", 42, Some("test-chat"), "new-42");
        let mut app = make_test_app(BoardData {
            assignments: vec![new_asg],
            ..BoardData::default()
        });
        app.pending_chat_resume = Some(make_pending_resume("old-42", 42, Some("test-chat")));
        let rebound = app.maybe_bind_pending_resume();
        assert!(
            rebound,
            "#361: test-chat continuation must rebind when a new test-chat assignment appears",
        );
        assert!(
            app.pending_chat_resume.is_none(),
            "pending_chat_resume must be cleared after a successful rebind",
        );
        assert_eq!(
            app.watch_focused,
            Some("new-42".to_string()),
            "watch_focused must point to the new assignment after rebind",
        );
    }

    /// #361 regression: new-issue-chat continuation must rebind when the new
    /// assignment is also "new-issue-chat".
    #[test]
    fn maybe_bind_pending_resume_rebinds_new_issue_chat() {
        let new_asg = make_resume_candidate("running", 7, Some("new-issue-chat"), "new-7");
        let mut app = make_test_app(BoardData {
            assignments: vec![new_asg],
            ..BoardData::default()
        });
        app.pending_chat_resume = Some(make_pending_resume("old-7", 7, Some("new-issue-chat")));
        let rebound = app.maybe_bind_pending_resume();
        assert!(
            rebound,
            "#361: new-issue-chat continuation must rebind when a new new-issue-chat assignment appears",
        );
        assert!(app.pending_chat_resume.is_none());
        assert_eq!(app.watch_focused, Some("new-7".to_string()));
    }

    /// Regression: refinement-type continuation still rebinds (pre-existing
    /// behaviour must not break after the #361 type-aware change).
    #[test]
    fn maybe_bind_pending_resume_still_rebinds_refinement() {
        let new_asg = make_resume_candidate("running", 5, Some("refinement"), "new-5");
        let mut app = make_test_app(BoardData {
            assignments: vec![new_asg],
            ..BoardData::default()
        });
        app.pending_chat_resume = Some(make_pending_resume("old-5", 5, Some("refinement")));
        let rebound = app.maybe_bind_pending_resume();
        assert!(
            rebound,
            "refinement continuation must still rebind after #361 type-aware change",
        );
        assert!(app.pending_chat_resume.is_none());
        assert_eq!(app.watch_focused, Some("new-5".to_string()));
    }

    /// Cross-type mismatch: old_type="refinement" but new assignment is
    /// "test-chat" → must NOT rebind (different chat sessions on the same
    /// issue should not cross-contaminate each other).
