    #[test]
    fn pending_merge_queue_depth_badge_color_logic() {
        // Verify the badge color selection: amber for > 5, muted for 1–5,
        // None for 0.  Exercises the colour decision independent of the
        // sidebar rendering path.
        let amber = Color::rgb(220, 160, 40);
        let muted = Color::rgb(160, 140, 100);

        // depth = 0 → no badge
        let badge_0: Option<Badge> = if 0 > 5 {
            Some(Badge::colored("Q:0", amber))
        } else if 0 > 0 {
            Some(Badge::colored("Q:0", muted))
        } else {
            None
        };
        assert!(badge_0.is_none(), "depth 0 should produce no badge");

        // depth = 3 → muted badge
        let badge_3: Option<Badge> = if 3 > 5 {
            Some(Badge::colored("Q:3", amber))
        } else if 3 > 0 {
            Some(Badge::colored("Q:3", muted))
        } else {
            None
        };
        assert!(badge_3.is_some(), "depth 3 should produce a badge");
        assert_eq!(badge_3.unwrap().fg, Some(muted), "depth 3 must be muted");

        // depth = 6 → amber badge
        let badge_6: Option<Badge> = if 6 > 5 {
            Some(Badge::colored("Q:6", amber))
        } else if 6 > 0 {
            Some(Badge::colored("Q:6", muted))
        } else {
            None
        };
        assert!(badge_6.is_some(), "depth 6 should produce a badge");
        assert_eq!(badge_6.unwrap().fg, Some(amber), "depth 6 must be amber");
    }

    // ── #541: issue fuzzy finder ──────────────────────────────────────────────

    #[test]
    fn fuzzy_score_empty_query_always_matches() {
        assert_eq!(fuzzy_score("", "anything"), Some((0, Vec::new())));
        assert_eq!(fuzzy_score("", ""), Some((0, Vec::new())));
    }

    #[test]
    fn fuzzy_score_subsequence_match() {
        // "fc" matches "FuzzyComplex" in order (case-insensitive)
        assert!(fuzzy_score("fc", "FuzzyComplex").is_some());
        // "cf" does NOT match in that order
        assert!(fuzzy_score("cf", "FuzzyComplex").is_none());
        // Consecutive characters score higher than non-consecutive.
        let consec = fuzzy_score("ab", "ab").unwrap().0;
        let non_consec = fuzzy_score("ab", "axb").unwrap().0;
        assert!(consec > non_consec, "consecutive run should score higher");
        // Matched positions are returned.
        let (_, positions) = fuzzy_score("fc", "FuzzyComplex").unwrap();
        assert!(!positions.is_empty(), "positions must be non-empty for a match");
        // Empty query always matches with no positions.
        let (score, positions) = fuzzy_score("", "anything").unwrap();
        assert_eq!(score, 0);
        assert!(positions.is_empty());
    }

